class _TrieNode:
    __slots__ = ('child', 'count')

    def __init__(self):
        self.child = [None, None]
        self.count = 0

class Solution:
    def maximumStrongPairXor(self, nums):
        arr = sorted(nums)
        n = len(arr)
        bits = 19
        root = _TrieNode()
        size = 0

        def insert(x):
            node = root
            for b in range(bits, -1, -1):
                bit = (x >> b) & 1
                if node.child[bit] is None:
                    node.child[bit] = _TrieNode()
                node = node.child[bit]
                node.count += 1

        def remove(x):
            node = root
            for b in range(bits, -1, -1):
                bit = (x >> b) & 1
                node = node.child[bit]
                node.count -= 1

        def query(x):
            node = root
            best = 0
            for b in range(bits, -1, -1):
                bit = (x >> b) & 1
                want = 1 - bit
                if node.child[want] is not None and node.child[want].count > 0:
                    best |= (1 << b)
                    node = node.child[want]
                else:
                    node = node.child[bit]
            return best

        left = 0
        best = 0
        for right in range(n):
            while arr[left] * 2 < arr[right]:
                remove(arr[left])
                left += 1
                size -= 1
            insert(arr[right])
            size += 1
            if size > 0:
                best = max(best, query(arr[right]))
        return best

