class TrieNode {
    constructor() { this.child = [null, null]; this.count = 0; }
}

var maximumStrongPairXor = function(nums) {
    const arr = nums.slice().sort((a, b) => a - b);
    const n = arr.length;
    const bits = 19;
    const root = new TrieNode();
    let size = 0;

    const insert = (x) => {
        let node = root;
        for (let b = bits; b >= 0; b--) {
            const bit = (x >> b) & 1;
            if (!node.child[bit]) node.child[bit] = new TrieNode();
            node = node.child[bit];
            node.count += 1;
        }
    };
    const remove = (x) => {
        let node = root;
        for (let b = bits; b >= 0; b--) {
            const bit = (x >> b) & 1;
            node = node.child[bit];
            node.count -= 1;
        }
    };
    const query = (x) => {
        let node = root;
        let best = 0;
        for (let b = bits; b >= 0; b--) {
            const bit = (x >> b) & 1;
            const want = 1 - bit;
            if (node.child[want] && node.child[want].count > 0) {
                best |= (1 << b);
                node = node.child[want];
            } else {
                node = node.child[bit];
            }
        }
        return best;
    };

    let left = 0, best = 0;
    for (let right = 0; right < n; right++) {
        while (arr[left] * 2 < arr[right]) {
            remove(arr[left]);
            left++;
            size--;
        }
        insert(arr[right]);
        size++;
        if (size > 0) {
            best = Math.max(best, query(arr[right]));
        }
    }
    return best;
};
